class SocialMediaModel {  bool? success;  List<SocialMediaData>? data;  SocialMediaModel({this.success, this.data});  SocialMediaModel.fromJson(Map<String, dynamic> json) {    success = json['success'];    if (json['data'] != null) {      data = <SocialMediaData>[];      json['data'].forEach((v) {        data!.add(new SocialMediaData.fromJson(v));      });    }  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['success'] = this.success;    if (this.data != null) {      data['data'] = this.data!.map((v) => v.toJson()).toList();    }    return data;  }}class SocialMediaData {  int? id;  String? name;  String? link;  String? icon;  SocialMediaData({this.id, this.name, this.link, this.icon});  SocialMediaData.fromJson(Map<String, dynamic> json) {    id = json['id'];    name = json['name'];    link = json['link'];    icon = json['icon'];  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['id'] = this.id;    data['name'] = this.name;    data['link'] = this.link;    data['icon'] = this.icon;    return data;  }}